import React from 'react';
import './App.css';
import './index.css';

function App() {
  const [count, setCount] = React.useState(0);

  const onClickMinus = () => {
    if(count !== 0) {
      setCount(count - 1);
    }
  };

  const onClickPlus = () => {
    setCount(count + 1);
  };

  return (
    <div className="App">
       <div className='counter'>
             <h2 className="title">Счётчик:</h2>
             <h1 className="output">{count}</h1>
             <div className='block_buttons'>
                <button onClick={onClickMinus} className="Minus">- Minus</button>
                <button onClick={onClickPlus} className="Plus">Plus +</button>
             </div>
       </div>
    </div>
  );
}

export default App;
